import httpx
token = secrets['token']
cookie = secrets.get('cookie', '')
headers = {'Authorization': 'Bearer ' + token, 'Content-Type': 'application/json'}
if cookie: headers['Cookie'] = 'd=' + cookie
r = httpx.get('https://slack.com/api/users.list', headers=headers, params={'limit': 200}, timeout=15).json()
if not r.get('ok'): result = {'ok': False, 'error': r.get('error', 'unknown')}
else:
    search = (params.get('search') or '').lower()
    users = []
    for u in r.get('members', []):
        if u.get('deleted') or u.get('is_bot'): continue
        name = u.get('real_name') or u.get('name') or ''
        display = u.get('profile', {}).get('display_name') or ''
        if not search or search in name.lower() or search in display.lower():
            users.append({'id': u['id'], 'name': u.get('real_name') or u.get('name'), 'display_name': display, 'email': u.get('profile', {}).get('email')})
    result = {'ok': True, 'users': users}

