import httpx
token = secrets['token']
cookie = secrets.get('cookie', '')
headers = {'Authorization': 'Bearer ' + token, 'Content-Type': 'application/json'}
if cookie: headers['Cookie'] = 'd=' + cookie
r = httpx.post('https://slack.com/api/client.counts', headers=headers, json={}, timeout=15).json()
if not r.get('ok'): result = {'ok': False, 'error': r.get('error', 'unknown')}
else:
    unread = []
    for ch in r.get('channels', []):
        if ch.get('has_unreads'): unread.append({'id': ch['id'], 'type': 'channel', 'mention_count': ch.get('mention_count', 0), 'latest': ch.get('latest')})
    for im in r.get('ims', []):
        if im.get('has_unreads'): unread.append({'id': im['id'], 'type': 'dm', 'mention_count': im.get('dm_count', 0), 'latest': im.get('latest')})
    for mpim in r.get('mpims', []):
        if mpim.get('has_unreads'): unread.append({'id': mpim['id'], 'type': 'mpim', 'mention_count': mpim.get('dm_count', 0), 'latest': mpim.get('latest')})
    for item in unread:
        info = httpx.get('https://slack.com/api/conversations.info', headers=headers, params={'channel': item['id']}, timeout=15).json()
        ch = info.get('channel', {})
        if ch.get('is_im') and ch.get('user'):
            u = httpx.get('https://slack.com/api/users.info', headers=headers, params={'user': ch['user']}, timeout=15).json()
            item['name'] = u.get('user', {}).get('real_name') or u.get('user', {}).get('name') or item['id']
        else:
            item['name'] = ch.get('name') or item['id']
    result = {'ok': True, 'unread': unread}
